"""SELF-CONTAINED Kaggle kernel -- Rubik's-Cube Coding System, full-system benchmark.

ONE CA-opcode core -> all 18 language faces, plus the geometric (tangentialism)
fleet router. No repo clone, no pip install: the 18 dialects + roundabout logic
are inlined (base64) and the router is inlined verbatim. stdlib + numpy only.
Auto-generated by scripts/kaggle_auto/build_comprehensive_kernel.py -- do not edit.
"""

import base64
import json
import math
