# ---- B1: emit throughput -----------------------------------------------------
def b1_emit(n, length, seed=7):
    rng = random.Random(seed)
    progs = [rand_prog(length, rng) for _ in range(n)]
    t0 = time.perf_counter()
    files = lines = chars = 0
    for p in progs:
        for lang in LANGS:
            s = emit(p, lang)
            files += 1
            lines += s.count("\n")  # output already ends in \n -> true line count
            chars += len(s)
    dt = time.perf_counter() - t0
    return dict(
        languages=len(LANGS),
        programs=n,
        ops=length,
        files=files,
        seconds=dt,
        programs_per_s=n / dt,
        files_per_s=files / dt,
        kloc_per_s=lines / 1000 / dt,
        mchars_per_s=chars / 1e6 / dt,
    )


# ---- B2: roundabout parity (defined undefined-zones) -------------------------
def b2_roundabouts():
    cases = [("div0", ["eq", "div"], "ZeroDivisionError"), ("sqrt_neg", ["sub", "sqrt"], "ValueError")]
    out = {}
    for tag, prog, want_exc in cases:
        raw_exc = None
        try:
            run_python(prog, safe=False)
        except BaseException as e:  # pin the exact type rather than swallow all
            raw_exc = type(e).__name__
        safe_val = run_python(prog, safe=True)
        out[tag] = dict(
            raw_exc=raw_exc,
            raw_raises_expected=(raw_exc == want_exc),
            safe_value=safe_val,
            safe_defined=(safe_val == 0.0),
        )
    # safe-mode emits for every language without error, and differs from raw on the op
    emit_ok = 0
    for lang in LANGS:
        try:
            safe_src = emit(["add", "div", "sqrt", "mod"], lang, safe=True)
            raw_src = emit(["add", "div", "sqrt", "mod"], lang, safe=False)
            if safe_src and safe_src != raw_src:
                emit_ok += 1
        except Exception:
            pass
    out["safe_emit_langs"] = emit_ok
    out["total_langs"] = len(LANGS)
    return out


# ---- B3a: emitter shape self-check (NOT a compile proof) ----------------------
def b3_shape(n, length, seed=11):
    """An emitter invariant, honestly labelled: every emit is well-formed (boilerplate
    present AND delimiters balanced). This is NOT evidence the code compiles -- that is
    B3b below. Delimiter balance is the one part that could actually fail on a bad
    template, so it is a real (if weak) structural signal beyond the tautological parts."""
    rng = random.Random(seed)
    progs = [rand_prog(length, rng) for _ in range(n)]
    total = ok = balanced = 0
    for p in progs:
        for lang in LANGS:
            for safe in (False, True):
                s = emit(p, lang, runnable=True, safe=safe)
                total += 1
                d = DIALECTS[lang]
                shape_ok = s.endswith("\n") and "tongue_fn" in s and (not d["fn_close"] or d["fn_close"][-1] in s)
                bal = s.count("(") == s.count(")") and s.count("{") == s.count("}") and s.count("[") == s.count("]")
                ok += shape_ok
                balanced += bal
    return dict(
        programs=n,
        langs=len(LANGS),
        checks=total,
        shape_ok=ok,
        balanced=balanced,
        shape_pct=100.0 * ok / total,
        balanced_pct=100.0 * balanced / total,
    )


# ---- B3b: REAL cross-language compile + run numeric parity --------------------
# The honest validity test: actually build & run each language whose toolchain is
# present on this node, and check it computes the SAME number python does. Languages
# with no toolchain here are reported as skipped -- never silently counted as passing.
_TOOLCHAINS = {
    "c": dict(ext="c", build=["gcc", "-O2", "-o", "{exe}", "{src}", "-lm"], run=["{exe}"]),
    "cpp": dict(ext="cpp", build=["g++", "-O2", "-o", "{exe}", "{src}"], run=["{exe}"]),
    "rust": dict(ext="rs", build=["rustc", "-O", "-o", "{exe}", "{src}"], run=["{exe}"]),
    "javascript": dict(ext="js", run=["node", "{src}"]),
    "typescript": dict(ext="ts", run=["ts-node", "{src}"]),
    "go": dict(ext="go", run=["go", "run", "{src}"]),
    "ruby": dict(ext="rb", run=["ruby", "{src}"]),
    "php": dict(ext="php", run=["php", "{src}"]),
    "lua": dict(ext="lua", run=["lua", "{src}"]),
    "julia": dict(ext="jl", run=["julia", "{src}"]),
    "java": dict(ext="java", fname="Main.java", build=["javac", "{src}"], run=["java", "-cp", "{dir}", "Main"]),
    "kotlin": dict(
        ext="kt", build=["kotlinc", "{src}", "-include-runtime", "-d", "{exe}.jar"], run=["java", "-jar", "{exe}.jar"]
    ),
    "scala": dict(ext="scala", run=["scala", "{src}"]),
    "swift": dict(ext="swift", run=["swift", "{src}"]),
    "haskell": dict(ext="hs", run=["runghc", "{src}"]),
    "csharp": dict(ext="cs", run=["dotnet", "script", "{src}"]),
    "zig": dict(ext="zig", run=["zig", "run", "{src}"]),
}


def _toolchain_present(spec):
    tool = (spec.get("build") or spec["run"])[0]
    return shutil.which(tool) is not None


def b3_compile(nprog=4, length=8, seed=17, timeout=25):
    rng = random.Random(seed)
    progs, refs = [], []
    while len(progs) < nprog:  # only well-defined programs (clean ref)
        p = rand_prog(length, rng)
        try:
            refs.append(float(run_python(p, safe=False)))
            progs.append(p)
        except Exception:
            continue
    per_lang = {}
    tmp = tempfile.mkdtemp(prefix="cube_")
    for lang in LANGS:
        spec = _TOOLCHAINS.get(lang)
        # python: always available, executed in-process
        if lang == "python":
            okc = sum(1 for p, r in zip(progs, refs) if abs(float(run_python(p, safe=False)) - r) < 1e-6)
            per_lang["python"] = dict(present=True, ok=okc, n=len(progs))
            continue
        if not spec or not _toolchain_present(spec):
            per_lang[lang] = dict(present=False, ok=0, n=len(progs))
            continue
        okc = 0
        for i, (p, r) in enumerate(zip(progs, refs)):
            d = os.path.join(tmp, "%s_%d" % (lang, i))
            os.makedirs(d, exist_ok=True)
            src = os.path.join(d, spec.get("fname", "prog.%s" % spec["ext"]))
            exe = os.path.join(d, "prog")
            with open(src, "w", encoding="utf-8") as fh:
                fh.write(emit(p, lang, runnable=True, safe=False))
            sub = lambda c: [x.replace("{src}", src).replace("{exe}", exe).replace("{dir}", d) for x in c]
            try:
                if "build" in spec:
                    b = subprocess.run(sub(spec["build"]), capture_output=True, timeout=timeout, cwd=d)
                    if b.returncode != 0:
                        continue
                run = subprocess.run(sub(spec["run"]), capture_output=True, timeout=timeout, cwd=d, text=True)
                if run.returncode != 0 or not run.stdout.strip():
                    continue
                got = float(run.stdout.strip().split()[-1])
                if abs(got - r) < 1e-6:
                    okc += 1
            except Exception:
                continue
        per_lang[lang] = dict(present=True, ok=okc, n=len(progs))
    shutil.rmtree(tmp, ignore_errors=True)
    present = [l for l in LANGS if per_lang[l]["present"]]
    fully_ok = [l for l in present if per_lang[l]["ok"] == len(progs)]
    return dict(
        programs=len(progs),
        per_lang=per_lang,
        present=present,
        present_count=len(present),
        fully_parity=fully_ok,
        fully_parity_count=len(fully_ok),
    )


def b3_exec_parity(length=12):
    """Python safe==raw where the math is already defined (roundabouts don't change defined results)."""
    parity = ok = 0
    rng = random.Random(13)
    for _ in range(200):
        p = rand_prog(length, rng)
        try:
            raw = run_python(p, safe=False)
        except Exception:
            continue
        parity += 1
        if run_python(p, safe=True) == raw:
            ok += 1
    return dict(checked=parity, ok=ok)


# ---- B4: geometric routing (tangentialism) vs round-robin --------------------
def b4_routing(sizes=(30, 120, 480), seed=7):
    # agents run in PARALLEL, so the metric that reflects wall-time is makespan =
    # the busiest agent's summed cost, not the fleet-wide total. Geometry balances
    # load AND respects tongue affinity, so it wins on makespan even at saturation.
    fleet = [Agent("%s-agent" % t, {t: 1.0}) for t in TONGUES]
    runs = []
    for ntask in sizes:
        rng = np.random.default_rng(seed)
        tasks = []
        for i in range(ntask):
            prof = {t: float(rng.random()) for t in TONGUES}
            if i % 3 == 0:
                dom = TONGUES[i % 6]
                prof = {t: (1.0 if t == dom else 0.1 * float(rng.random())) for t in TONGUES}
            tasks.append(Task("task%04d" % i, prof))
        t0 = time.perf_counter()
        routes = route_fleet(fleet, tasks, pressure=0.6, tour=False)
        dt = time.perf_counter() - t0
        geo_total = sum(r.total_cost for r in routes)
        geo_make = max((r.total_cost for r in routes), default=0.0)
        # round-robin per-agent makespan: chunk by index, sum each agent's distances
        rr_loads = [0.0] * len(fleet)
        for i, t in enumerate(tasks):
            a = fleet[i % len(fleet)]
            rr_loads[i % len(fleet)] += finsler_distance(a.pos, t.profile, a.tongue)
        rr_total, rr_make = sum(rr_loads), max(rr_loads)
        runs.append(
            dict(
                tasks=ntask,
                geo_total=geo_total,
                rr_total=rr_total,
                geo_makespan=geo_make,
                rr_makespan=rr_make,
                makespan_cheaper_pct=100.0 * (1 - geo_make / rr_make) if rr_make else 0.0,
                total_cheaper_pct=100.0 * (1 - geo_total / rr_total) if rr_total else 0.0,
                route_seconds=dt,
            )
        )
    return runs


# ---- B5: scaling sweep -------------------------------------------------------
def b5_scaling(counts=(1000, 4000, 16000), length=12):
    out = []
    for n in counts:
        r = b1_emit(n, length, seed=3)
        out.append(
            dict(
                programs=n, programs_per_s=r["programs_per_s"], files_per_s=r["files_per_s"], kloc_per_s=r["kloc_per_s"]
            )
        )
    return out


